    subj_conf_data.set("NotOnOrAfter", _iso(not_on_or_after))
    subj_conf_data.set("Recipient", recipient)

    conditions = etree.SubElement(assertion, "{urn:oasis:names:tc:SAML:2.0:assertion}Conditions")
    conditions.set("NotBefore", _iso(not_before))
    conditions.set("NotOnOrAfter", _iso(not_on_or_after))

    audience_restriction = etree.SubElement(conditions, "{urn:oasis:names:tc:SAML:2.0:assertion}AudienceRestriction")
    audience_el = etree.SubElement(audience_restriction, "{urn:oasis:names:tc:SAML:2.0:assertion}Audience")
