def _build_saml_response_xml(
    *,
    in_response_to: str,
    destination: str,
    acs_url: str,
    audience: str,
    nameid_value: str,
    attributes: Dict[str, Any],
    relay_state: Optional[str],
) -> str:
    issue_instant = _now_utc()
    not_before = issue_instant - datetime.timedelta(seconds=30)
    not_on_or_after = issue_instant + datetime.timedelta(minutes=5)
    authn_instant = issue_instant
    response_id = _gen_id("_r")
    session_index = _gen_id("_s")

    NSMAP = {
        "samlp": "urn:oasis:names:tc:SAML:2.0:protocol",
        "saml": "urn:oasis:names:tc:SAML:2.0:assertion",
        "ds": "http://www.w3.org/2000/09/xmldsig#",
    }

    response = etree.Element("{urn:oasis:names:tc:SAML:2.0:protocol}Response", nsmap=NSMAP)
    response.set("ID", response_id)
    response.set("Version", "2.0")
    response.set("IssueInstant", _iso(issue_instant))
    response.set("Destination", destination)
    response.set("InResponseTo", in_response_to)

    issuer = etree.SubElement(response, "{urn:oasis:names:tc:SAML:2.0:assertion}Issuer")
    issuer.text = IDP_ENTITY_ID

    status = etree.SubElement(response, "{urn:oasis:names:tc:SAML:2.0:protocol}Status")
    status_code = etree.SubElement(status, "{urn:oasis:names:tc:SAML:2.0:protocol}StatusCode")
    status_code.set("Value", "urn:oasis:names:tc:SAML:2.0:status:Success")

    assertion = _build_assertion_xml(
        in_response_to=in_response_to,
        destination=destination,
        audience=audience,
        recipient=acs_url,
        nameid_value=nameid_value,
        nameid_format=DEFAULT_NAMEID_FORMAT,
        attributes=attributes,
        session_index=session_index,
        issue_instant=issue_instant,
        not_before=not_before,
        not_on_or_after=not_on_or_after,
        authn_instant=authn_instant,
    )

    assertion_signed = _sign_assertion(assertion)
    response.append(assertion_signed)

    xml_bytes = etree.tostring(
        response,
        xml_declaration=True,
        encoding="UTF-8",
        pretty_print=False,
    )
    return xml_bytes.decode("utf-8")


